      mmpi: {
        name: 'MMPI (Dépistage du bien-être)',
        tagline: 'Auto-évaluation du bien-être psychologique',
        description: 'Inspiré de la structure du MMPI, ce dépistage éducatif du bien-être explore votre état psychologique actuel à travers des domaines tels que l\'humeur, le fonctionnement social, l\'énergie et la perception de soi.',
        disclaimer: '⚠️ Ceci est un dépistage éducatif simplifié inspiré des concepts MMPI. Le vrai MMPI-2 est un instrument clinique de 567 items administré par des psychologues agréés. Cet outil n\'est pas diagnostique.',
        questions: {
          '1': { text: 'Dans l\'ensemble, je me sens heureux(se) et positif(ve) dans ma vie.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '2': { text: 'Je me sens souvent triste, vide ou déprimé(e) sans raison claire.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '3': { text: 'Dans ma vie quotidienne, je me sens intéressé(e) et enthousiaste à propos de diverses choses.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '4': { text: 'Je me sens souvent anxieux(se), tendu(e) ou sur les nerfs.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '5': { text: 'J\'ai généralement assez d\'énergie pour faire les choses que je veux faire.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '6': { text: 'J\'ai du mal à trouver la motivation même pour les choses qui comptaient pour moi.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '7': { text: 'Après avoir dormi, je me sens reposé(e) et rafraîchi(e).', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '8': { text: 'Je me sens connecté(e) aux personnes dans ma vie.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '9': { text: 'Je me sens souvent isolé(e), incompris(e) ou déconnecté(e) des autres.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '10': { text: 'Les interactions sociales me procurent du plaisir plutôt que de m\'épuiser.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '11': { text: 'Dans l\'ensemble, j\'ai une bonne image de qui je suis.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '12': { text: 'Je me sens souvent comme un fardeau pour les autres.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '13': { text: 'Je crois avoir de vraies forces et qualités.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '14': { text: 'Quand les choses tournent mal, je sens généralement que je peux y faire face.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '15': { text: 'J\'ai du mal à contrôler mes inquiétudes une fois qu\'elles commencent.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '16': { text: 'Je me sens maître de ma vie et de mes choix.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '17': { text: 'Les petits problèmes me semblent souvent insurmontables.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '18': { text: 'Je suis gêné(e) par des symptômes physiques inexpliqués — maux de tête, fatigue ou tension.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '19': { text: 'Je prends généralement soin de ma santé physique.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '20': { text: 'Ma vie me semble avoir un sens et aller vers des choses qui comptent pour moi.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '21': { text: 'Je me demande souvent si ce que je fais a une quelconque importance.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '22': { text: 'J\'ai des objectifs ou des choses que j\'attends avec impatience.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '23': { text: 'Je peux généralement profiter du moment présent sans être coincé(e) dans le passé ou m\'inquiéter de l\'avenir.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '24': { text: 'Je sens que je grandis et progresse dans la vie.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '25': { text: 'J\'ai des personnes dans ma vie vers qui je peux me tourner quand j\'ai besoin de soutien.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '26': { text: 'Je me sens en sécurité dans mon environnement quotidien.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '27': { text: 'Je suis capable de gérer le stress sans me sentir submergé(e).', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '28': { text: 'La plupart du temps, je sens que mes besoins émotionnels sont satisfaits.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '29': { text: 'J\'ai récemment vécu un événement qui a significativement perturbé mon bien-être.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
          '30': { text: 'Dans l\'ensemble, je suis satisfait(e) de ma vie.', options: ['Tout à fait en désaccord', 'Plutôt en désaccord', 'Plutôt d\'accord', 'Tout à fait d\'accord'] },
        }
      },
